// Calcular fase lunar actual
const knownNewMoon = new Date('2000-01-06T18:14:00Z');
const synodicMonth = 29.53058867;
const now = new Date();
const diff = (now - knownNewMoon) / (1000 * 60 * 60 * 24);
const age = ((diff % synodicMonth) + synodicMonth) % synodicMonth;
const illumination = Math.round(((1 - Math.cos(2 * Math.PI * age / synodicMonth)) / 2) * 100);
const phaseIndex = Math.round(age / synodicMonth * 8) % 8;
const phaseNames = ['Luna Nueva', 'Creciente', 'Cuarto Creciente', 'Gibosa Creciente', 'Luna Llena', 'Gibosa Menguante', 'Cuarto Menguante', 'Menguante'];

return {
  moon_phase: phaseNames[phaseIndex],
  moon_illumination: illumination,
  moon_phase_index: phaseIndex
};

// Extraer datos de las ramas combinadas
const zones = $input.all()[0]?.json?.data?.zones || [];
const moonData = $input.all()[1]?.json || {};
const weatherLP = $input.all()[2]?.json || {};
const weatherTF = $input.all()[3]?.json || {};

// Calcular promedio Bortle
const avgBortle = zones.length > 0
  ? zones.reduce((s, z) => s + z.bortle_scale, 0) / zones.length
  : 5;

// Extraer datos meteorológicos
const temps = [weatherLP?.main?.temp, weatherTF?.main?.temp].filter(t => t != null);
const humidities = [weatherLP?.main?.humidity, weatherTF?.main?.humidity].filter(h => h != null);
const winds = [weatherLP?.wind?.speed, weatherTF?.wind?.speed].filter(w => w != null);
const cloudsLP = weatherLP?.clouds?.all ?? null;
const cloudsTF = weatherTF?.clouds?.all ?? null;
const cloudinessValues = [cloudsLP, cloudsTF].filter(c => c != null);

const avgTemp = temps.length > 0 ? temps.reduce((s, t) => s + t, 0) / temps.length : null;
const avgHumidity = humidities.length > 0 ? humidities.reduce((s, h) => s + h, 0) / humidities.length : null;
const avgWind = winds.length > 0 ? winds.reduce((s, w) => s + w, 0) / winds.length : null;
const avgCloudiness = cloudinessValues.length > 0 ? cloudinessValues.reduce((s, c) => s + c, 0) / cloudinessValues.length : null;

// Calcular puntuaciones (0-10)
const bortleScore = ((9 - avgBortle) / 8) * 10;
const cloudScore = avgCloudiness !== null ? Math.max(0, 10 - avgCloudiness / 10) : 5;
const moonScore = moonData.moon_illumination !== undefined
  ? 10 - (moonData.moon_illumination / 10)
  : 5;
const windScore = avgWind !== null ? Math.max(0, 10 - avgWind * 2) : 5;

// Ponderación
const overallScore = Math.round(
  (bortleScore * 0.40 + cloudScore * 0.25 + moonScore * 0.20 + windScore * 0.15) * 10
) / 10;

return {
  date: new Date().toISOString().split('T')[0],
  overall_score: overallScore,
  astro_score: Math.round((bortleScore * 0.5 + cloudScore * 0.3 + moonScore * 0.2) * 10) / 10,
  photo_score: Math.round((bortleScore * 0.3 + cloudScore * 0.4 + windScore * 0.3) * 10) / 10,
  tourism_score: Math.round((bortleScore * 0.2 + cloudScore * 0.3 + (10 - avgWind) * 0.3 + 5 * 0.2) * 10) / 10,
  avg_bortle: Math.round(avgBortle * 10) / 10,
  avg_cloudiness: avgCloudiness !== null ? Math.round(avgCloudiness * 10) / 10 : null,
  avg_humidity: avgHumidity !== null ? Math.round(avgHumidity * 10) / 10 : null,
  avg_wind_speed: avgWind !== null ? Math.round(avgWind * 10) / 10 : null,
  avg_temperature: avgTemp !== null ? Math.round(avgTemp * 10) / 10 : null,
  moon_phase: moonData.moon_phase || null,
  moon_illumination: moonData.moon_illumination ?? null,
  source: 'n8n'
};
